int main() {
    int T; scanf("%d", &T);
    while (T--) {
        char S[1001]; scanf("%s", S);
        int N = strlen(S), cnt = 0;
        for (int i = 0; i < N; i++) {
            if (i > 0 && S[i] == S[i-1]) continue;
            if (i > 0 && (S[i-1] == '0' && S[i] == '1' || S[i-1] == '1' && S[i] == '0')) cnt++;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

